import os
import sqlite3
import json
import re
from flask import Flask, request, render_template, jsonify, g

app = Flask(__name__)
app.config['SECRET_KEY'] = 'AetherisSecret_9921'
DATABASE = '/tmp/aetheris_orbitals.db'

def get_db():
    db = getattr(g, '_database', None)
    if db is None:
        db = g._database = sqlite3.connect(DATABASE)
        db.row_factory = sqlite3.Row
    return db

@app.teardown_appcontext
def close_connection(exception):
    db = getattr(g, '_database', None)
    if db is not None:
        db.close()

def security_filter(data):
    # Expert WAF: Blocks keywords followed by spaces or common separators
    # but has a logic flaw: it doesn't account for parenthesis or specific control chars
    blacklist = ['SELECT', 'UNION', 'WHERE', 'OR', 'AND', '--', '/\\*', ' ']
    for word in blacklist:
        if re.search(rf"\b{word}\b", data, re.IGNORECASE):
            return False
    if ' ' in data:
        return False
    return True

@app.route('/')
def index():
    return render_template('index.html')

@app.route('/dashboard')
def dashboard():
    db = get_db()
    satellites = db.execute('SELECT * FROM orbital_assets').fetchall()
    return render_template('dashboard.html', satellites=satellites)

@app.route('/telemetry/<int:sat_id>')
def telemetry(sat_id):
    db = get_db()
    satellite = db.execute('SELECT * FROM orbital_assets WHERE id = ?', (sat_id,)).fetchone()
    # Secure parameterized query here
    logs = db.execute('SELECT * FROM telemetry_logs WHERE sat_id = ? ORDER BY timestamp DESC LIMIT 10', (sat_id,)).fetchall()
    return render_template('telemetry.html', satellite=satellite, logs=logs)

@app.route('/api/v1/archive/export', methods=['POST'])
def export_archive():
    # Requirement: X-Debug-Mode header
    if request.headers.get('X-Debug-Mode') != '1':
        return jsonify({"error": "Internal debug mode required for legacy export access."}), 403

    data = request.get_json()
    if not data or 'query_params' not in data:
        return jsonify({"error": "Missing required field: query_params"}), 400

    params = data['query_params']
    asset_id = params.get('asset_id', 'SAT-01')
    # VULNERABLE POINT: The 'sort_on' parameter is directly concatenated
    sort_on = params.get('sort_on', 'timestamp')

    if not security_filter(sort_on):
        return jsonify({"error": "Security violation: blacklisted keyword or illegal character detected"}), 400

    try:
        db = get_db()
        # The query uses a controlled list of columns for the SELECT part, but allows injection in ORDER BY
        query = f"SELECT id, sat_id, timestamp, metric_value FROM telemetry_logs WHERE sat_id = ? ORDER BY {sort_on} ASC"
        results = db.execute(query, (asset_id,)).fetchall()

        output = []
        for r in results:
            output.append(dict(r))
        return jsonify(output)
    except Exception as e:
        return jsonify({"error": "Database error", "detail": str(e)}), 500

@app.route('/system/status')
def status():
    # Red Herring endpoint
    return render_template('status.html')

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=5000)

